1	import type { Env } from "../types";
2	import { sseResponse, patchElements, mergeFragments } from "../sse/helpers";
3	import { getUser, loadProgram, getQueueItems, getRoutineMappings } from "../storage/queries";
4	import { getNextRoutine, getCompletedRoutines } from "../domain/queue";
5	import { computeUpcoming } from "../domain/reflow";
6	import { setupPage } from "../fragments/setup";
7	import { carsCard, heroRoutineCard, completedSection, upcomingSection, syncButton } from "../fragments/today";
8	import { todayString } from "../utils/date";
9	import { decryptAesGcm } from "../utils/crypto";
10	
11	/** SSE: Today page — CARs card, hero session, completed, upcoming */
12	export async function handleTodaySSE(env: Env, userId: string, tz?: string, opts?: { showCredentials?: boolean }): Promise<Response> {
13	  const user = await getUser(env.DB, userId);
14	  if (!user) {
15	    return sseResponse(
16	      patchElements(setupPage(), { selector: "#content", mode: "inner" })
17	    );
18	  }
19	
20	  const { program, programId } = await loadProgram(env.DB, userId);
21	  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
22	  const dailyRoutine = program.routines.find((r) => r.isDaily);
23	
24	  const items = await getQueueItems(env.DB, userId, programId);
25	  const today = todayString(tz);
26	
27	  // Look up routine mappings for deep links
28	  const routineMappings = await getRoutineMappings(env.DB, userId, programId);
29	  const routineToHevyId = new Map(
30	    routineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
31	  );
32	
33	  const fragments: string[] = [];
34	
35	  const dailyDoneToday = dailyRoutine && user.daily_completed_date === today;
36	
37	  if (dailyRoutine && !dailyDoneToday) {
38	    fragments.push(patchElements(carsCard(dailyRoutine, routineToHevyId.get(dailyRoutine.id)), { selector: "#content", mode: "inner" }));
39	  }
40	
41	  // Hero session card — next pending
42	  const nextItem = getNextRoutine(items);
43	  if (nextItem) {
44	    const routine = routineMap.get(nextItem.routine_id);
45	    if (routine) {
46	      const mode = (dailyRoutine && !dailyDoneToday) ? "append" : "inner";
47	      fragments.push(
48	        patchElements(heroRoutineCard(routine, nextItem), { selector: "#content", mode })
49	      );
50	    }
51	  }
52	
53	  // Completed today
54	  const completed = getCompletedRoutines(items, today);
55	  const completedData = completed.map((item) => ({
56	    title: routineMap.get(item.routine_id)?.title ?? item.routine_id,
57	    hevy_workout_data: item.hevy_workout_data,
58	  }));
59	  if (dailyDoneToday) {
60	    completedData.unshift({ title: dailyRoutine.title, hevy_workout_data: null });
61	  }
62	  if (completedData.length > 0) {
63	    fragments.push(
64	      patchElements(completedSection(completedData), { selector: "#content", mode: "append" })
65	    );
66	  }
67	
68	  // Upcoming (next 5 sessions)
69	  const template = program.weekTemplates.find((t) => t.id === user.template_id);
70	  if (template) {
71	    const pendingItems = items.filter((i) => i.status === "pending").sort((a, b) => a.position - b.position);
72	    // Skip the first pending (already shown as hero) for upcoming
73	    const upcomingPending = pendingItems.slice(1);
74	    // Convert JS getDay() (0=Sun) to template convention (0=Mon)
75	    const jsDay = new Date(today + "T12:00:00Z").getDay();
76	    const todayDow = jsDay === 0 ? 6 : jsDay - 1;
77	    const upcoming = computeUpcoming(upcomingPending, template, program.routines, 5, todayDow);
78	    if (upcoming.length > 0) {
79	      fragments.push(
80	        patchElements(upcomingSection(upcoming), { selector: "#content", mode: "append" })
81	      );
82	    }
83	  }
84	
85	  // Sync button at the bottom — only decrypt bearer token when just registered
86	  let bearerToken: string | null = null;
87	  if (opts?.showCredentials && user.webhook_bearer_token) {
88	    bearerToken = await decryptAesGcm(user.webhook_bearer_token, env.ENCRYPTION_KEY);
89	  }
90	  fragments.push(
91	    patchElements(syncButton(user.webhook_id, bearerToken, user.last_sync_at, tz), { selector: "#content", mode: "append" })
92	  );
93	
94	  return sseResponse(mergeFragments(fragments));
95	}
